import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Improved Facebook/Meta AEM Campaign Reporting","description":"","frontmatter":{"title":"Improved Facebook/Meta AEM Campaign Reporting","slug":"improved-facebookmeta-aem-campaign-reporting"},"headers":[],"relativePath":"account-hub/improved-facebookmeta-aem-campaign-reporting.md","filePath":"account-hub/improved-facebookmeta-aem-campaign-reporting.md"}'),o={name:"account-hub/improved-facebookmeta-aem-campaign-reporting.md"};function n(s,e,l,p,c,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<p>Meta&#39;s Aggregate Event Measurement (AEM) campaigns will get new reporting updates in Branch. Get the details here 👍</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Starting July 2nd, Meta’s Aggregate Event Measurement (<a href="https://www.facebook.com/business/help/721422165168355?id=1877298665783613" target="_blank" rel="noreferrer">AEM</a>) attributed conversion events will be available in the Branch Dashboard and various data exports. This update offers customers additional insights into Meta attribution data, improving measurement and analysis of their performance.</p><p>This update will not affect other attribution sources or channels within Branch, which ensures existing processes and data from other sources remain unchanged.</p><h3 id="data-availability" tabindex="-1">Data Availability <a class="header-anchor" href="#data-availability" aria-label="Permalink to &quot;Data Availability&quot;">​</a></h3><ul><li><p>AEM attributed conversions will be represented throughout Branch Dashboard reporting.</p></li><li><p>AEM attributed conversion events will be available in log-level reporting. This includes opens and downstream conversion events.</p><ul><li>Installs attributed to AEM are not available in log-level reporting.</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Looking to learn more about Meta AEM? View our guide <a href="./enable-app-aggregated-event-measurement-support.html">here</a>.</p></div>',7)])])}const h=a(o,[["render",n]]);export{u as __pageData,h as default};
